import{_ as a,o as l,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F08: 產能利用率與資產擴張 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3189_景碩/20260423/F08_產能利用率與資產擴張_投資研究員.md","filePath":"審計報告庫/財務審計/3189_景碩/20260423/F08_產能利用率與資產擴張_投資研究員.md"}'),t={name:"審計報告庫/財務審計/3189_景碩/20260423/F08_產能利用率與資產擴張_投資研究員.md"};function r(n,e,s,p,d,c){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="f08-產能利用率與資產擴張-投資研究員審計報告" tabindex="-1">F08: 產能利用率與資產擴張 - 投資研究員審計報告 <a class="header-anchor" href="#f08-產能利用率與資產擴張-投資研究員審計報告" aria-label="Permalink to &quot;F08: 產能利用率與資產擴張 - 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>判定景碩(3189)產能利用率趨勢、固定資產擴張速度及資本支出效率，識別公司處於重資產擴張期、輕資產化轉型或老化瓶頸期。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至2025年Q4(2025年度完整財報)及2026年Q1法說會最新公開數據，景碩固定資產(PP&amp;E)由2023年末31,623M增至2025年末41,937M(+32.6%)，同期營收由26,832M增至39,370M(+46.7%)，營收成長係數1.43遠高於擴產速度。2026年1月宣布3年235億擴產計畫(六廠ABF載板)，產能利用率持續高檔。判定處於明確的「播種期→收割期過渡階段」，業績爆發動能強勁。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：S (優)</strong></p><p>評分依據：</p><ul><li>營收成長率/固定資產成長率=1.43&gt;1.2，屬典型「生意太好、產能跟不上需求」的優質格局。</li><li>折舊費用由2023年5,282M增至2025年7,159M(+35.5%)，與PP&amp;E增速一致，無異常減值。</li><li>營運活動現金流2025年8,093M完全覆蓋Capex 6,117M，擴產資金全自償，無需稀釋股權。</li><li>2026年1月董事會通過235億/3年擴產計畫(單廠月產1,000萬顆ABF)，產能全被客戶預訂，預示2027年起營收將顯著躍遷。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>1. 生意火熱度 (Business Momentum)</strong></p><p>景碩設備利用率趨勢可從以下指標間接推斷：</p><ul><li>毛利率走勢：2023年27.4%→2024年27.6%→2025年22.2%(2025年毛利率下滑主因折舊費用增加7,159M及營業成本由26,098M升至31,037M，反映產能滿載後邊際成本上升)。</li><li>營收逐季加速：2025年Q1 8,620M→Q2 9,564M→Q3 10,356M→Q4 10,811M，每季環比增長3-12%。</li><li>2025年Q4法說會揭露HPC營收佔比24%，AI相關ABF載板需求強勁。</li></ul><p><strong>2. 擴產價值 (Expansion Value)</strong></p><p>CIP(在建工程)與預付設備款的驗證：</p><ul><li>資產負債表「其他非流動資產」(含CIP+預付設備)由2023末16,075M→2024末12,732M→2025末8,124M，持續下降反映在建設備陸續轉固(GFA增加)。PP&amp;E則由31,623M→36,409M→41,937M同步上升，驗證CIP轉固效率良好。</li><li>2025年Capex 6,117M(現金流量表實際支出)低於折舊7,159M，為短期產能爬坡緩衝期。</li><li>2026年起3年235億擴產(年均78.3億)，較過往年均100億略低，但精準集中於ABF高層數載板，屬「精準擴產」策略。</li></ul><p>近期重大擴產時程：</p><ul><li>六廠ABF擴產：月增1,000萬顆，預計2027年開出。</li><li>設備交期受日東坊材料(電子級玻纖)產能限制，預估2027年後材料瓶頸緩解。</li></ul><p><strong>3. 投資安全性 (Safety Margin)</strong></p><p>重資產防禦力測試：</p><ul><li>2025年負債比48.3%(長借112.0B+短借30.5B vs 權益413.7B)，較2024年49.8%下降。</li><li>利息保障倍數(2025Q4)：稅前淨利1,055M/利息費用~391M=12.23倍，遠高於安全水位5倍。</li><li>折舊7,159M佔營運現金流8,093M之88.5%，意味即使營收衰退10%，營運現金流仍足以支撐當前產能維護支出。</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩正處於載板產業最稀缺的「產能全開且訂單可見度高的擴產布局期」。不同於2022年ABF擴產潮中出現的供過於求，本次AI驅動的高層數ABF需求具備結構性成長動能(CoWoS封裝、2.5D/3D封裝持續放量)，景碩的3年235億擴產計畫是基於客戶長期合約確認後的產能補充，而非投機性擴張。</p><p><strong>三項關鍵利好信號：</strong></p><ol><li><strong>營收成長領先資產擴張</strong>：46.7% vs 32.6%的增速差，意味產能釋放後立即被市場吸收，無庫存堆積風險。</li><li><strong>CIP轉固節奏健康</strong>：CIP連續下降而PP&amp;E上升，驗證工程管理能力。</li><li><strong>擴產資金自償能力</strong>：營運現金流8,093M &gt; Capex 6,117M，不須依賴增資或大幅舉債。</li></ol><p><strong>唯一需關注的風險</strong>：折舊費用的攀升(2025年7,159M→預估2027年將達8.5-9B)。若新產能良率爬坡不及預期，短線毛利率可能持續承壓。但長期看，這是「播種期」的必要代價，2027年新廠量產後將進入「收割期」。</p><p>判定景碩為「成長股之星(擴產收割期)」，資產利用效率極佳，業績爆發力具備扎實的財務物理支撐。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py balance_sheet 3189 2023-01-01 2026-04-23 --df</code> (科目：PropertyPlantAndEquipment/OtherNoncurrentAssets)</li><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py cash_flow 3189 2023-01-01 2026-04-23 --df</code> (科目：PropertyAndPlantAndEquipment/Depreciation/CashFlowsFromOperatingActivities)</li><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py revenue 3189 2023-01-01 2026-04-23 --df</code> (月營收走勢)</li><li><code>MoneyDJ理財網</code>: moneydj.com/kmdj/news/newsviewer.aspx?a=98a37d16 (景碩明年資本支出上看95億加碼六廠ABF擴產)</li><li><code>經濟日報</code>: money.udn.com/money/story/5612/9427027 (景碩2026年台灣六廠擴ABF載板產能應對AI需求)</li><li><code>工商時報</code>: ctee.com.tw/news/20260415700277-439901 (景碩ABF擴產助攻報導)</li></ul>',29)])])}const u=a(t,[["render",r]]);export{h as __pageData,u as default};
